module RefModule(
  input [3:0] in1,
  input [3:0] in2,
  output reg [1:0] out
);always @(*) begin
  wire [3:0] _tap_in1 = in1 & {4{1'b1}};

    if(in1 == in2) begin
      out <= 2'b00;
    end else if(in1 > in2) begin
      out <= 2'b01;
    end else if(in1 < in2) begin
      out <= 2'b10;
    end else begin
      out <= 2'b11;
    end
  end

endmodule
